scwin.excelDown = function(){
    // {"fileName":"CFS수출입고조회.xlsx","type":"4+8+16"}
    const infoArr = [];
    const options = {
        fileName : "CFS수출입고조회.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "CFS수출입고조회",
        // startRowIndex: 2,
        type : "1",
        // removeColumns: "0,21",
        // hiddenVisible : true,
        // useSubTotal :"true", 
        // useSubTotalData  : "true",
        oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
        evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
    };
    $c.data.downloadGridViewExcel(gr_cfs, options, infoArr);
};
